// deep_link_state.dart
part of 'deep_link_bloc.dart';

@immutable
abstract class DeepLinkState extends Equatable {
  const DeepLinkState();
}

class DeepLinkInitial extends DeepLinkState {
  const DeepLinkInitial();

  @override
  List<Object?> get props => [];
}

class DeepLinkReceived extends DeepLinkState {
  final Uri uri;
  final Map<String, String> params;

  const DeepLinkReceived(this.uri, this.params);

  @override
  List<Object?> get props => [uri, params];
}

class DeepLinkProcessed extends DeepLinkState {
  const DeepLinkProcessed();

  @override
  List<Object?> get props => [];
}

// deep_link_event.dart
abstract class DeepLinkEvent extends Equatable {
  const DeepLinkEvent();
}

class DeepLinkOpened extends DeepLinkEvent {
  final Uri uri;
  const DeepLinkOpened(this.uri);

  @override
  List<Object?> get props => [uri];
}

class DeepLinkHandled extends DeepLinkEvent {
  const DeepLinkHandled();

  @override
  List<Object?> get props => [];
}

class DeepLinkBloc extends Bloc<DeepLinkEvent, DeepLinkState> {
  DeepLinkBloc() : super(const DeepLinkInitial()) {
    on<DeepLinkOpened>(_onDeepLinkOpened);
    on<DeepLinkHandled>(_onDeepLinkHandled);
  }

  Future<void> _onDeepLinkOpened(DeepLinkOpened event, Emitter<DeepLinkState> emit) async {
    // Parse URI parameters (example: /product/123?referrer=email)
    final pathSegments = event.uri.pathSegments;
    final queryParams = event.uri.queryParameters;
    final params = <String, String>{};

    // Example: parse product ID from path
    if (pathSegments.isNotEmpty && pathSegments.first == 'product' && pathSegments.length > 1) {
      params['productId'] = pathSegments[1];
    }

    // Add all query parameters
    params.addAll(queryParams);

    emit(DeepLinkReceived(event.uri, params));
  }

  Future<void> _onDeepLinkHandled(DeepLinkHandled event, Emitter<DeepLinkState> emit) async {
    emit(const DeepLinkProcessed());
  }
}

final router = GoRouter(
  initialLocation: '/',
  routes: [
    GoRoute(
      path: '/',
      name: 'home',
      builder: (context, state) => HomePage(),
    ),
    GoRoute(
      path: '/product/:id',
      name: 'product',
      builder: (context, state) => ProductPage(productId: state.params['id']!),
    ),
    GoRoute(
      path: '/profile/:userId',
      name: 'profile',
      builder: (context, state) => ProfilePage(userId: state.params['userId']!),
    ),
  ],
  redirect: (context, state) {
    // Example: check if deep link is pending in BLoC
    final deepLinkState = context.read<DeepLinkBloc>().state;
    if (deepLinkState is DeepLinkReceived) {
      final uri = deepLinkState.uri;
      // Determine where to navigate based on the URI
      if (uri.pathSegments.isNotEmpty) {
        if (uri.pathSegments.first == 'product') {
          final productId = uri.pathSegments[1];
          return '/product/$productId';
        } else if (uri.pathSegments.first == 'profile') {
          final userId = uri.pathSegments[1];
          return '/profile/$userId';
        }
      }
      // If no matching route, fallback to home
      return '/';
    }
    return null; // no redirect
  },
);

void main() async {
  WidgetsFlutterBinding.ensureInitialized();

  // Parse initial deep link if any
  final initialUri = _getInitialUri();

  final deepLinkBloc = DeepLinkBloc();
  if (initialUri != null) {
    deepLinkBloc.add(DeepLinkOpened(initialUri));
  }

  runApp(MyApp(deepLinkBloc: deepLinkBloc));
}

Uri? _getInitialUri() {
  // For platforms where initial route is a deep link
  final initialRoute = WidgetsBinding.instance.window.defaultRouteName;
  if (initialRoute.startsWith('http://') || initialRoute.startsWith('https://')) {
    return Uri.parse(initialRoute);
  }
  return null;
}

class MyApp extends StatelessWidget {
  final DeepLinkBloc deepLinkBloc;
  const MyApp({required this.deepLinkBloc});

  @override
  Widget build(BuildContext context) {
    return BlocProvider(
      create: (_) => deepLinkBloc,
      child: MaterialApp.router(
        routerConfig: router,
      ),
    );
  }
}

import 'package:app_links/app_links.dart';

class DeepLinkService {
  final DeepLinkBloc deepLinkBloc;
  final AppLinks _appLinks = AppLinks();

  DeepLinkService(this.deepLinkBloc) {
    _init();
  }

  void _init() async {
    // Handle initial link (if any) – already handled in main
    // Listen to future links
    _appLinks.uriLinkStream.listen((Uri? uri) {
      if (uri != null) {
        deepLinkBloc.add(DeepLinkOpened(uri));
      }
    });
  }
}

// In main or a service locator
final deepLinkBloc = DeepLinkBloc();
final deepLinkService = DeepLinkService(deepLinkBloc);

class ProductPage extends StatelessWidget {
  final String productId;
  const ProductPage({required this.productId});

  @override
  Widget build(BuildContext context) {
    // Optionally, you can listen to deep link events to show a banner
    return BlocListener<DeepLinkBloc, DeepLinkState>(
      listenWhen: (previous, current) =>
          current is DeepLinkReceived &&
          current.params['productId'] == productId &&
          previous is! DeepLinkReceived,
      listener: (context, state) {
        if (state is DeepLinkReceived) {
          // Show a message that the user arrived via deep link
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(content: Text('Opened via deep link from ${state.params['referrer'] ?? 'unknown'}')),
          );
          // Mark as handled so it doesn't show again
          context.read<DeepLinkBloc>().add(DeepLinkHandled());
        }
      },
      child: Scaffold(
        appBar: AppBar(title: Text('Product $productId')),
        body: Center(child: Text('Product details')),
      ),
    );
  }
}

void main() {
  group('DeepLinkBloc', () {
    blocTest<DeepLinkBloc, DeepLinkState>(
      'emits DeepLinkReceived when product link opened',
      build: () => DeepLinkBloc(),
      act: (bloc) => bloc.add(DeepLinkOpened(Uri.parse('https://example.com/product/123?ref=email'))),
      expect: () => [
        DeepLinkReceived(
          Uri.parse('https://example.com/product/123?ref=email'),
          {'productId': '123', 'ref': 'email'},
        ),
      ],
    );

    blocTest<DeepLinkBloc, DeepLinkState>(
      'emits DeepLinkProcessed after handled',
      build: () => DeepLinkBloc(),
      seed: () => DeepLinkReceived(Uri.parse('https://example.com/product/123'), {'productId': '123'}),
      act: (bloc) => bloc.add(DeepLinkHandled()),
      expect: () => [const DeepLinkProcessed()],
    );
  });
}

