// Simplified deep link simulation for demo
class DeepLinkCubit extends Cubit<Uri?> {
  DeepLinkCubit() : super(null);
  void handleDeepLink(String link) => emit(Uri.parse(link));
  void clear() => emit(null);
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return BlocProvider(
      create: (_) => DeepLinkCubit(),
      child: MaterialApp(
        title: 'Deep Link Demo',
        home: HomePage(),
        routes: {
          '/product': (context) => ProductPage(),
        },
      ),
    );
  }
}

class HomePage extends StatelessWidget {
  final TextEditingController linkController = TextEditingController();

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Deep Link Demo')),
      body: Padding(
        padding: EdgeInsets.all(16),
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            TextField(
              controller: linkController,
              decoration: InputDecoration(
                labelText: 'Enter deep link URL',
                hintText: 'https://example.com/product/123',
              ),
            ),
            SizedBox(height: 20),
            ElevatedButton(
              onPressed: () {
                final link = linkController.text;
                if (link.isNotEmpty) {
                  context.read<DeepLinkCubit>().handleDeepLink(link);
                }
              },
              child: Text('Simulate Deep Link'),
            ),
            SizedBox(height: 20),
            BlocConsumer<DeepLinkCubit, Uri?>(
              listener: (context, uri) {
                if (uri != null && uri.pathSegments.isNotEmpty && uri.pathSegments.first == 'product') {
                  Navigator.pushNamed(context, '/product', arguments: uri);
                  context.read<DeepLinkCubit>().clear();
                }
              },
              builder: (context, uri) => Container(),
            ),
          ],
        ),
      ),
    );
  }
}

class ProductPage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    final uri = ModalRoute.of(context)!.settings.arguments as Uri?;
    final productId = uri?.pathSegments.length == 2 ? uri.pathSegments[1] : 'unknown';
    return Scaffold(
      appBar: AppBar(title: Text('Product Details')),
      body: Center(child: Text('Product ID: $productId')),
    );
  }
}
